SELECT a.chnl_id, a.chnl_nm, a.chnl_disp_nm, a.track_id, a.track_nm, f.artist_id reqArtistId, f.artist_nm reqArtsitNm, a.agency_id, b.album_id, e.artist_id, e.artist_nm, c.album_img_size size, c.album_img_url url, a.create_dtime, a.update_dtime, a.track_cnt trackCount, a.img_size, a.img_url, a.track_sn, a.renew_track_cnt, a.renew_dtime, a.trackCreateDtime, a.trackUpdateDtime, a.trackRenewDtime, a.svc_streaming_yn, a.svc_drm_yn, a.free_yn, a.rank FROM ( SELECT a.chnl_id, a.chnl_nm, a.chnl_disp_nm, a.renew_track_cnt, a.renew_dtime, a.track_id, a.track_nm, a.agency_id, a.album_id, a.create_dtime, a.update_dtime, a.track_cnt, a.track_sn, a.reprsnt_artist_id, a.img_size, a.img_url, a.trackCreateDtime trackCreateDtime, a.trackUpdateDtime trackUpdateDtime, a.trackRenewDtime trackRenewDtime, a.svc_streaming_yn, a.svc_drm_yn, a.free_yn, @curRank:=IF(@prevChnlId = a.chnl_id,@curRank + 1,1) AS rank, @prevChnlId:=a.chnl_id FROM ( SELECT chnl.chnl_id, chnl.renew_track_cnt, chnl.renew_dtime, chnl.chnl_nm, chnl.chnl_disp_nm, ( SELECT COUNT(*) FROM tb_map_chnl_track aa JOIN tb_track bb ON aa.track_id = bb.track_id AND bb.disp_status_yn= 'Y' AND now() BETWEEN bb.disp_start_dtime AND bb.disp_end_dtime WHERE aa.chnl_id = chnl.chnl_id
) AS track_cnt, chnl.create_dtime, chnl.update_dtime, chnl.img_url, chnl.img_size, c.track_id, c.track_nm, c.agency_id, c.album_id, c.reprsnt_artist_id, c.create_dtime trackCreateDtime, c.update_dtime trackUpdateDtime, c.svc_streaming_yn, c.svc_drm_yn, c.free_yn, b.create_dtime trackRenewDtime, b.track_sn FROM ( SELECT a.*, IF(c.img_url is null, '', c.img_url) as img_url, IF(c.img_size is null, '', c.img_size) as img_size FROM tb_chnl a
LEFT OUTER JOIN tb_map_category_chnl b ON a.chnl_id = b.chnl_id LEFT OUTER JOIN ( SELECT * FROM tb_img_mang WHERE img_content_type IN ('MOOD', 'SITTN') ) AS c ON b.category_id = c.img_content_id AND c.img_disp_type = 'CHNL_MAIN' AND c.dfk_type = 'EVERY' AND c.os_type = #{osType}
LEFT OUTER JOIN tb_map_svc_genre_chnl b ON a.chnl_id = b.chnl_id LEFT OUTER JOIN tb_map_img_rcmmd_img c ON b.svc_genre_id = c.img_content_id AND c.img_disp_type = 'MAIN_TOP' AND c.dfk_type = 'EVERY' AND c.os_type = #{osType} AND c.rcmmd_type_id = 'RC_PRF_CN' AND c.img_content_type = 'GENRE'
WHERE a.chnl_id IN
#{channelId}
AND a.disp_status_type = 'Y' GROUP BY a.chnl_id
) chnl INNER JOIN tb_map_chnl_track b ON chnl.chnl_id = b.chnl_id INNER JOIN tb_track c ON b.track_id = c.track_id AND c.disp_status_yn = 'Y' AND now() BETWEEN c.disp_start_dtime AND c.disp_end_dtime ORDER BY FIELD(chnl.chnl_id,
#{channelId}
) , b.track_sn ASC ) a ) a INNER JOIN ted_album b ON a.album_id = b.album_id AND b.disp_status_yn = 'Y' AND now() BETWEEN b.disp_start_dtime AND b.disp_end_dtime LEFT OUTER JOIN tb_album_img c ON b.album_id = c.album_id LEFT OUTER JOIN ted_trackartist d ON a.track_id =d.track_id AND d.rp_yn = 'Y' LEFT OUTER JOIN ted_artist e ON d.artist_id = e.artist_id LEFT OUTER JOIN ted_artist f ON f.artist_id = a.reprsnt_artist_id , (SELECT @curRank:=0, @prevChnlId:=0) r WHERE a.rank <= #{trackLimitSize}

